class Solution:
    def countPairs(self, deliciousness):
        MOD = 10**9 + 7
        n = len(deliciousness)
        count = 0
        for i in range(n):
            for j in range(i + 1, n):
                s = deliciousness[i] + deliciousness[j]
                if s > 0 and (s & (s - 1)) == 0:
                    count += 1
        return count % MOD

