class Solution:
    def countPairs(self, deliciousness):
        MOD = 10**9 + 7
        seen = {}
        answer = 0
        max_sum = 1 << 22
        powers = [1 << b for b in range(22)]
        for v in deliciousness:
            for p in powers:
                need = p - v
                if need < 0:
                    continue
                if need in seen:
                    answer = (answer + seen[need]) % MOD
            seen[v] = seen.get(v, 0) + 1
        return answer % MOD

solutions.javascript:
var countPairs = function(deliciousness) {
    const MOD = 1000000007;
    const seen = new Map();
    let answer = 0;
    const powers = [];
    for (let b = 0; b < 22; b++) powers.push(1 << b);
    for (const v of deliciousness) {
        for (const p of powers) {
            const need = p - v;
            if (need < 0) continue;
            if (seen.has(need)) {
                answer = (answer + seen.get(need)) % MOD;
            }
        }
        seen.set(v, (seen.get(v) || 0) + 1);
    }
    return answer % MOD;
};
